import React, { useState, useEffect } from 'react';
import { getRooms, getRoomTypes, createRoom, updateRoom, deleteRoom, createRoomType, updateRoomType, uploadRoomImage } from '../api';
import toast from 'react-hot-toast';

function Modal({ title, onClose, children }) {
  return (
    <div style={{ position: 'fixed', inset: 0, zIndex: 600, background: 'rgba(0,0,0,0.45)', display: 'flex', alignItems: 'center', justifyContent: 'center', padding: 24 }} onClick={onClose}>
      <div style={{ background: 'white', borderRadius: 16, width: '100%', maxWidth: 520, boxShadow: '0 24px 64px rgba(0,0,0,0.2)', maxHeight: '90vh', overflowY: 'auto' }} onClick={e => e.stopPropagation()}>
        <div style={{ padding: '20px 24px', borderBottom: '1px solid var(--gray-100)', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
          <h3 style={{ fontWeight: 800, fontSize: '1rem', color: 'var(--navy)' }}>{title}</h3>
          <button onClick={onClose} style={{ background: 'none', border: 'none', fontSize: '1.1rem', color: 'var(--gray-400)', cursor: 'pointer' }}>✕</button>
        </div>
        <div style={{ padding: 24 }}>{children}</div>
      </div>
    </div>
  );
}

export default function RoomsPage() {
  const [rooms, setRooms]           = useState([]);
  const [roomTypes, setRoomTypes]   = useState([]);
  const [loading, setLoading]       = useState(true);
  const [tab, setTab]               = useState('rooms');
  const [modal, setModal]           = useState(null); // null | 'addRoom' | 'editRoom' | 'addType' | 'editType' | 'images'
  const [editing, setEditing]       = useState(null);
  const [saving, setSaving]         = useState(false);
  const [filterType, setFilterType] = useState('');

  const [roomForm, setRoomForm]     = useState({ room_number: '', room_type: '', floor: '', status: 'available' });
  const [typeForm, setTypeForm]     = useState({ name: 'standard', description: '', capacity: 2, base_price: 0, amenities: '' });
  const [imageFile, setImageFile]   = useState(null);

  const load = () => {
    Promise.all([getRooms(), getRoomTypes()]).then(([r, t]) => {
      setRooms(r.data.results || r.data);
      setRoomTypes(t.data.results || t.data);
    }).finally(() => setLoading(false));
  };
  useEffect(() => { load(); }, []);

  const openAddRoom  = () => { setRoomForm({ room_number: '', room_type: roomTypes[0]?.id || '', floor: '', status: 'available' }); setEditing(null); setModal('addRoom'); };
  const openEditRoom = (r) => { setRoomForm({ room_number: r.room_number, room_type: r.room_type?.id, floor: r.floor, status: r.status }); setEditing(r); setModal('editRoom'); };
  const openAddType  = () => { setTypeForm({ name: 'standard', description: '', capacity: 2, base_price: 0, amenities: '' }); setEditing(null); setModal('addType'); };
  const openEditType = (t) => { setTypeForm({ name: t.name, description: t.description, capacity: t.capacity, base_price: t.base_price, amenities: (t.amenities || []).join(', ') }); setEditing(t); setModal('editType'); };

  const saveRoom = async () => {
    setSaving(true);
    try {
      const data = { ...roomForm, floor: parseInt(roomForm.floor), room_type: parseInt(roomForm.room_type) };
      if (editing) { await updateRoom(editing.id, data); toast.success('Room updated.'); }
      else         { await createRoom(data);             toast.success('Room created.'); }
      setModal(null); load();
    } catch (e) {
      const err = e.response?.data;
      toast.error(err?.room_number?.[0] || err?.detail || 'Failed to save room.');
    } finally { setSaving(false); }
  };

  const saveType = async () => {
    setSaving(true);
    try {
      // Validate required fields
      if (!typeForm.base_price || parseFloat(typeForm.base_price) <= 0) {
        toast.error('Base price is required and must be greater than 0');
        setSaving(false);
        return;
      }

      if (!typeForm.name) {
        toast.error('Room type name is required');
        setSaving(false);
        return;
      }

      if (!typeForm.capacity || parseInt(typeForm.capacity) <= 0) {
        toast.error('Capacity must be at least 1');
        setSaving(false);
        return;
      }

      const amenities = typeForm.amenities.split(',').map(a => a.trim()).filter(Boolean);
      const data = { 
        name: typeForm.name,
        description: typeForm.description || '',
        capacity: parseInt(typeForm.capacity), 
        base_price: parseFloat(typeForm.base_price), 
        amenities: amenities
      };

      console.log('Saving room type data:', data); // Debug log

      if (editing) { 
        await updateRoomType(editing.id, data); 
        toast.success('Room type updated.'); 
      } else { 
        await createRoomType(data);              
        toast.success('Room type created.'); 
      }
      setModal(null); 
      load();
    } catch (e) {
      console.error('Error saving room type:', e);
      console.error('Error response:', e.response);
      console.error('Error data:', e.response?.data);

      // Handle different error formats
      if (e.response?.data) {
        const errors = e.response.data;
        if (typeof errors === 'object') {
          const errorMessages = Object.entries(errors).map(([field, msgs]) => {
            if (field === 'non_field_errors') return msgs;
            return `${field}: ${Array.isArray(msgs) ? msgs.join(', ') : msgs}`;
          }).join('; ');
          toast.error(errorMessages);
        } else {
          toast.error(String(errors));
        }
      } else if (e.response?.status === 400) {
        toast.error('Validation error. Please check all fields are filled correctly.');
      } else {
        toast.error(e.response?.data?.detail || 'Failed to save room type.');
      }
    } finally { 
      setSaving(false); 
    }
  };

  const handleDeleteRoom = async (id) => {
    if (!window.confirm('Delete this room?')) return;
    try { await deleteRoom(id); toast.success('Room deleted.'); load(); }
    catch (e) { toast.error(e.response?.data?.detail || 'Cannot delete room with existing reservations.'); }
  };

  const saveImage = async () => {
    if (!imageFile) return;
    setSaving(true);
    try {
      const fd = new FormData(); 
      fd.append('image', imageFile); 
      fd.append('is_primary', 'true'); 
      fd.append('order', '0');
      await uploadRoomImage(editing.id, fd);
      toast.success('Image uploaded.'); 
      setModal(null); 
      setImageFile(null); 
      load();
    } catch (e) { 
      toast.error(e.response?.data?.detail || 'Upload failed.'); 
    }
    finally { setSaving(false); }
  };

  const filtered = filterType ? rooms.filter(r => r.room_type?.name === filterType) : rooms;

  return (
    <div style={{ padding: 32 }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 24 }}>
        <div>
          <h1 style={{ fontSize: '1.5rem', fontWeight: 800, color: 'var(--navy)', letterSpacing: '-0.02em' }}>Room Management</h1>
          <p style={{ fontSize: '0.85rem', color: 'var(--gray-400)', marginTop: 2 }}>Manage rooms and room types</p>
        </div>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn btn-outline" onClick={openAddType}>+ Add Room Type</button>
          <button className="btn btn-primary" onClick={openAddRoom}>+ Add Room</button>
        </div>
      </div>

      {/* Tabs */}
      <div style={{ display: 'flex', gap: 0, marginBottom: 20, borderBottom: '2px solid var(--gray-100)' }}>
        {[['rooms', 'Rooms'], ['types', 'Room Types']].map(([key, label]) => (
          <button key={key} onClick={() => setTab(key)} style={{ padding: '10px 20px', border: 'none', background: 'none', fontSize: '0.875rem', fontWeight: 600, cursor: 'pointer', color: tab === key ? 'var(--blue)' : 'var(--gray-400)', borderBottom: tab === key ? '2px solid var(--blue)' : '2px solid transparent', marginBottom: -2, transition: 'color 0.2s' }}>
            {label}
          </button>
        ))}
      </div>

      {tab === 'rooms' && (
        <>
          <div style={{ display: 'flex', gap: 8, marginBottom: 16, flexWrap: 'wrap' }}>
            {['', ...roomTypes.map(t => t.name)].map(type => (
              <button key={type} onClick={() => setFilterType(type)} style={{ padding: '6px 14px', borderRadius: 8, border: 'none', cursor: 'pointer', fontSize: '0.78rem', fontWeight: 600, background: filterType === type ? 'var(--blue)' : 'var(--gray-100)', color: filterType === type ? 'white' : 'var(--gray-600)', textTransform: 'capitalize', transition: 'all 0.2s' }}>
                {type || 'All'}
              </button>
            ))}
          </div>
          <div className="card">
            {loading ? <div style={{ padding: 40, textAlign: 'center', color: 'var(--gray-400)' }}>Loading...</div> : (
              <table className="table">
                <thead>
                  <tr>
                    <th>Room No.</th>
                    <th>Type</th>
                    <th>Floor</th>
                    <th>Status</th>
                    <th>Price/Night</th>
                    <th>Images</th>
                    <th>Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {filtered.map(r => (
                    <tr key={r.id}>
                      <td><span style={{ fontWeight: 700 }}>{r.room_number}</span></td>
                      <td><span style={{ textTransform: 'capitalize' }}>{r.room_type?.name}</span></td>
                      <td>Floor {r.floor}</td>
                      <td><span className={`badge badge-${r.status}`}>{r.status}</span></td>
                      <td>₱{Number(r.room_type?.base_price).toLocaleString()}</td>
                      <td>
                        <button className="btn btn-sm btn-outline" onClick={() => { setEditing(r); setModal('images'); }}>
                          📷 {r.images?.length || 0}
                        </button>
                      </td>
                      <td>
                        <div style={{ display: 'flex', gap: 6 }}>
                          <button className="btn btn-sm btn-outline" onClick={() => openEditRoom(r)}>Edit</button>
                          <button className="btn btn-sm btn-danger" onClick={() => handleDeleteRoom(r.id)}>Delete</button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </>
      )}

      {tab === 'types' && (
        <div className="card">
          <table className="table">
            <thead>
              <tr>
                <th>Name</th>
                <th>Capacity</th>
                <th>Base Price</th>
                <th>Amenities</th>
                <th>Actions</th>
              </tr>
            </thead>
            <tbody>
              {roomTypes.map(t => (
                <tr key={t.id}>
                  <td style={{ textTransform: 'capitalize', fontWeight: 600 }}>{t.name}</td>
                  <td>Up to {t.capacity} guests</td>
                  <td>₱{Number(t.base_price).toLocaleString()}/night</td>
                  <td style={{ fontSize: '0.8rem', color: 'var(--gray-600)' }}>{(t.amenities || []).join(', ') || '—'}</td>
                  <td><button className="btn btn-sm btn-outline" onClick={() => openEditType(t)}>Edit</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* Room Form Modal */}
      {(modal === 'addRoom' || modal === 'editRoom') && (
        <Modal title={modal === 'addRoom' ? 'Add New Room' : 'Edit Room'} onClose={() => setModal(null)}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            <div className="form-group">
              <label>Room Number</label>
              <input placeholder="e.g. 101" value={roomForm.room_number} onChange={e => setRoomForm(f => ({ ...f, room_number: e.target.value }))} />
            </div>
            <div className="form-group">
              <label>Room Type</label>
              <select value={roomForm.room_type} onChange={e => setRoomForm(f => ({ ...f, room_type: e.target.value }))}>
                {roomTypes.map(t => <option key={t.id} value={t.id}>{t.name}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Floor</label>
              <input type="number" placeholder="1" value={roomForm.floor} onChange={e => setRoomForm(f => ({ ...f, floor: e.target.value }))} />
            </div>
            <div className="form-group">
              <label>Status</label>
              <select value={roomForm.status} onChange={e => setRoomForm(f => ({ ...f, status: e.target.value }))}>
                <option value="available">Available</option>
                <option value="occupied">Occupied</option>
                <option value="maintenance">Maintenance</option>
              </select>
            </div>
            <div style={{ display: 'flex', gap: 10, marginTop: 8 }}>
              <button className="btn btn-outline" style={{ flex: 1, justifyContent: 'center' }} onClick={() => setModal(null)}>Cancel</button>
              <button className="btn btn-primary" style={{ flex: 2, justifyContent: 'center' }} onClick={saveRoom} disabled={saving}>{saving ? 'Saving...' : 'Save Room'}</button>
            </div>
          </div>
        </Modal>
      )}

      {/* Room Type Modal */}
      {(modal === 'addType' || modal === 'editType') && (
        <Modal title={modal === 'addType' ? 'Add Room Type' : 'Edit Room Type'} onClose={() => setModal(null)}>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 14 }}>
            <div className="form-group">
              <label>Type <span style={{ color: 'red' }}>*</span></label>
              <select value={typeForm.name} onChange={e => setTypeForm(f => ({ ...f, name: e.target.value }))}>
                <option value="standard">Standard</option>
                <option value="deluxe">Deluxe</option>
                <option value="suite">Suite</option>
              </select>
            </div>

            <div className="form-group">
              <label>Description</label>
              <textarea rows={3} value={typeForm.description} onChange={e => setTypeForm(f => ({ ...f, description: e.target.value }))} style={{ resize: 'vertical' }} placeholder="Optional description of the room type" />
            </div>

            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
              <div className="form-group">
                <label>Capacity (guests) <span style={{ color: 'red' }}>*</span></label>
                <input 
                  type="number" 
                  min={1} 
                  value={typeForm.capacity} 
                  onChange={e => setTypeForm(f => ({ ...f, capacity: e.target.value }))} 
                  required
                />
              </div>
              <div className="form-group">
                <label>Base Price (PHP) <span style={{ color: 'red' }}>*</span></label>
                <input 
                  type="number" 
                  min={0} 
                  step="0.01"
                  value={typeForm.base_price} 
                  onChange={e => setTypeForm(f => ({ ...f, base_price: e.target.value }))} 
                  required
                  placeholder="0.00"
                />
              </div>
            </div>

            <div className="form-group">
              <label>Amenities (comma separated)</label>
              <input 
                placeholder="WiFi, TV, Air Conditioning, Mini Bar" 
                value={typeForm.amenities} 
                onChange={e => setTypeForm(f => ({ ...f, amenities: e.target.value }))} 
              />
              <small style={{ color: 'var(--gray-400)', fontSize: '0.7rem' }}>Separate multiple amenities with commas</small>
            </div>

            <div style={{ display: 'flex', gap: 10, marginTop: 8 }}>
              <button className="btn btn-outline" style={{ flex: 1, justifyContent: 'center' }} onClick={() => setModal(null)}>Cancel</button>
              <button className="btn btn-primary" style={{ flex: 2, justifyContent: 'center' }} onClick={saveType} disabled={saving}>
                {saving ? 'Saving...' : (modal === 'addType' ? 'Create Type' : 'Update Type')}
              </button>
            </div>
          </div>
        </Modal>
      )}

      {/* Image Upload Modal */}
      {modal === 'images' && editing && (
        <Modal title={`Images — Room ${editing.room_number}`} onClose={() => { setModal(null); setImageFile(null); }}>
          <div style={{ marginBottom: 20 }}>
            <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 12 }}>
              {(editing.images || []).length === 0 ? 
                <p style={{ color: 'var(--gray-400)', fontSize: '0.85rem' }}>No images yet.</p> :
                editing.images.map(img => (
                  <div key={img.id} style={{ width: 100, height: 75, borderRadius: 8, overflow: 'hidden', border: '1px solid var(--gray-200)' }}>
                    <img src={img.image} alt="" style={{ width: '100%', height: '100%', objectFit: 'cover' }} />
                  </div>
                ))
              }
            </div>
          </div>
          <div className="form-group" style={{ marginBottom: 16 }}>
            <label>Upload New Image (max 5 total)</label>
            <input type="file" accept="image/*" onChange={e => setImageFile(e.target.files[0])} style={{ padding: 8 }} />
          </div>
          <button className="btn btn-primary" style={{ width: '100%', justifyContent: 'center' }} onClick={saveImage} disabled={saving || !imageFile}>
            {saving ? 'Uploading...' : 'Upload Image'}
          </button>
        </Modal>
      )}
    </div>
  );
}
